package cl.duoc.vetcontrol.notificacion.messaging;
import cl.duoc.vetcontrol.notificacion.service.NotificacionService; import org.slf4j.*; import org.springframework.kafka.annotation.KafkaListener; import org.springframework.stereotype.Component;
@Component
public class NotificationListener { private static final Logger log=LoggerFactory.getLogger(NotificationListener.class); private final NotificacionService service; public NotificationListener(NotificacionService service){this.service=service;} @KafkaListener(topics="cita-creada", groupId="notificacion-service") public void cita(String payload){log.info("Evento cita-creada: {}",payload);service.registrar("CITA", "Nueva cita registrada: "+payload);} @KafkaListener(topics="venta-creada", groupId="notificacion-service") public void venta(String payload){log.info("Evento venta-creada: {}",payload);service.registrar("VENTA", "Nueva venta registrada: "+payload);} @KafkaListener(topics="atencion-registrada", groupId="notificacion-service") public void atencion(String payload){service.registrar("ATENCION", "Atención registrada: "+payload);} }
